import{z}from"zod";import{v4 as uuidv4}from"uuid";import{checkWebSocketServerForUIProTool,getWebSocketServerForUIProTool}from"./utils.js";export const TOOL_SCHEMA_GET_FIGMA_COMPONENT_META=z.object({nodeIds:z.array(z.string()).optional()});export const TOOL_NAME_GET_FIGMA_COMPONENT_META="getFigmaComponentMeta";export const TOOL_DEFINITION_GET_FIGMA_COMPONENT_META={name:"getFigmaComponentMeta",description:"Fetch detailed metadata for Figma components including properties, variants, dimensions, total node count, and nested components. If no nodeIds are provided, uses currently selected nodes in Figma.",inputSchema:{type:"object",properties:{nodeIds:{type:"array",items:{type:"string"},description:"Optional array of Figma node IDs to fetch metadata for. If not provided, uses currently selected nodes."}},required:[]}};export async function runToolGetFigmaComponentMeta(args){try{const webSocketServer=getWebSocketServerForUIProTool(),serverCheckResult=checkWebSocketServerForUIProTool(webSocketServer);if(!serverCheckResult.valid)return serverCheckResult.data;const connectionManager=webSocketServer.getConnectionManager(),request={id:uuidv4(),type:"GET_FIGMA_COMPONENT_META",payload:args.nodeIds?{nodeIds:args.nodeIds}:void 0},response=await connectionManager.sendRequest(request,3e4);if(!response.success||response.error)return{isError:!0,content:[{type:"text",text:`Error fetching component metadata: ${response.error||"Unknown error"}`}]};if(!response.data||0===response.data.length)return{content:[{type:"text",text:"No component metadata received. Make sure you have selected component nodes in Figma or provided valid component node IDs."}]};const components=response.data.map((comp=>({id:comp.id,name:comp.name,dimensions:{width:comp.width,height:comp.height},properties:comp.properties||{},totalVariants:comp.totalVariants||0,totalNodes:comp.totalNodes||0,variantIds:comp.variantIds||[],nestedComponents:comp.nestedComponents||[]})));return{content:[{type:"text",text:`Successfully retrieved metadata for ${components.length} component(s):\n\n${JSON.stringify(components,null,2)}`}]}}catch(error){return{isError:!0,content:[{type:"text",text:`Error fetching component metadata: ${error.message||error}`}]}}}